            // --- 一般的な初期化エラー ---
            EVRInitError.Unknown => new EVRInitializeException("未知の初期化エラーが発生しました。", error),
            EVRInitError.Init_InstallationNotFound => new EVRInitializeException("OpenVRのインストールが見つかりません。", error),
            EVRInitError.Init_InstallationCorrupt => new EVRInitializeException("OpenVRのインストールが壊れています。", error),
            EVRInitError.Init_VRClientDLLNotFound => new EVRInitializeException("vrclient.dllが見つかりません。", error),
            EVRInitError.Init_FileNotFound => new EVRInitializeException("必要な構成ファイルが見つかりません。", error),
            EVRInitError.Init_FactoryNotFound => new EVRInitializeException("ファクトリインターフェースの取得に失敗しました。", error),
            EVRInitError.Init_InterfaceNotFound => new EVRInitializeException("要求されたインターフェースが見つかりません。", error),
            EVRInitError.Init_InvalidInterface => new EVRInitializeException("インターフェースが無効です。", error),
            EVRInitError.Init_UserConfigDirectoryInvalid => new EVRInitializeException("ユーザー設定ディレクトリが無効です。", error),
