            EVRInitError.Init_NoLogPath => new EVRInitializeException("ログパスが設定されていません。", error),
            EVRInitError.Init_PathRegistryNotWritable => new EVRInitializeException("パスレジストリに書き込めません。", error),
            EVRInitError.Init_AppInfoInitFailed => new EVRInitializeException("アプリケーション情報の初期化に失敗しました。", error),
