            EVRInitError.Init_NotSupportedWithCompositor => new EVRInitializeException("コンポジター使用時はサポートされません。", error),
            EVRInitError.Init_NotAvailableToUtilityApps => new EVRInitializeException("ユーティリティアプリでは利用できません。", error),
