            EVRInitError.Compositor_CreateMirrorTextures => new EVRCompositorInitializeException("ミラーテクスチャの作成に失敗しました。", error),
            EVRInitError.Compositor_CreateLastFrameRenderTexture => new EVRCompositorInitializeException("直前フレームレンダリングテクスチャの作成に失敗しました。", error),
            EVRInitError.Compositor_CreateMirrorOverlay => new EVRCompositorInitializeException("ミラーオーバーレイの作成に失敗しました。", error),
            EVRInitError.Compositor_FailedToCreateVirtualDisplayBackbuffer => new EVRCompositorInitializeException("仮想ディスプレイバックバッファの作成に失敗しました。", error),
            EVRInitError.Compositor_DisplayModeNotSupported => new EVRCompositorInitializeException("ディスプレイモードがサポートされていません。", error),
            EVRInitError.Compositor_CreateOverlayInvalidCall => new EVRCompositorInitializeException("オーバーレイ作成呼び出しが無効です。", error),
            EVRInitError.Compositor_CreateOverlayAlreadyInitialized => new EVRCompositorInitializeException("オーバーレイは既に初期化されています。", error),
            EVRInitError.Compositor_FailedToCreateMailbox => new EVRCompositorInitializeException("メールボックスの作成に失敗しました。", error),
            EVRInitError.Compositor_WindowInterfaceIsNull => new EVRCompositorInitializeException("ウィンドウインターフェースがnullです。", error),
            EVRInitError.Compositor_SystemLayerCreateInstance => new EVRCompositorInitializeException("システムレイヤーインスタンスの作成に失敗しました。", error),
            EVRInitError.Compositor_SystemLayerCreateSession => new EVRCompositorInitializeException("システムレイヤーセッションの作成に失敗しました。", error),

            // --- ベンダー固有エラー (Oculus/Meta等) ---
            EVRInitError.VendorSpecific_UnableToConnectToOculusRuntime => new EVRVendorSpecificInitializeException("Oculusランタイムに接続できません。", error),
            EVRInitError.VendorSpecific_WindowsNotInDevMode => new EVRVendorSpecificInitializeException("Windowsが開発者モードではありません。", error),
            EVRInitError.VendorSpecific_HmdFound_CantOpenDevice => new EVRVendorSpecificInitializeException("HMDデバイスを開けませんでした。", error),
            EVRInitError.VendorSpecific_HmdFound_UnableToRequestConfigStart => new EVRVendorSpecificInitializeException("HMD構成開始の要求に失敗しました。", error),
            EVRInitError.VendorSpecific_HmdFound_NoStoredConfig => new EVRVendorSpecificInitializeException("HMD内に保存された構成がありません。", error),
            EVRInitError.VendorSpecific_HmdFound_ConfigTooBig => new EVRVendorSpecificInitializeException("HMD構成データが大きすぎます。", error),
            EVRInitError.VendorSpecific_HmdFound_ConfigTooSmall => new EVRVendorSpecificInitializeException("HMD構成データが小さすぎます。", error),
            EVRInitError.VendorSpecific_HmdFound_UnableToInitZLib => new EVRVendorSpecificInitializeException("zlibの初期化に失敗しました。", error),
            EVRInitError.VendorSpecific_HmdFound_CantReadFirmwareVersion => new EVRVendorSpecificInitializeException("ファームウェアバージョンの読み取りに失敗しました。", error),
            EVRInitError.VendorSpecific_HmdFound_UnableToSendUserDataStart => new EVRVendorSpecificInitializeException("ユーザーデータ送信開始に失敗しました。", error),
            EVRInitError.VendorSpecific_HmdFound_UnableToGetUserDataStart => new EVRVendorSpecificInitializeException("ユーザーデータ取得開始に失敗しました。", error),
            EVRInitError.VendorSpecific_HmdFound_UnableToGetUserDataNext => new EVRVendorSpecificInitializeException("ユーザーデータ次フレーム取得に失敗しました。", error),
            EVRInitError.VendorSpecific_HmdFound_UserDataAddressRange => new EVRVendorSpecificInitializeException("ユーザーデータのアドレス範囲エラーです。", error),
            EVRInitError.VendorSpecific_HmdFound_UserDataError => new EVRVendorSpecificInitializeException("ユーザーデータエラーが発生しました。", error),
            EVRInitError.VendorSpecific_HmdFound_ConfigFailedSanityCheck => new EVRVendorSpecificInitializeException("HMD構成データの整合性チェックに失敗しました。", error),
            EVRInitError.VendorSpecific_OculusRuntimeBadInstall => new EVRVendorSpecificInitializeException("Oculusランタイムのインストールが不完全です。", error),

            // --- その他 ---
            EVRInitError.Steam_SteamInstallationNotFound => new EVRInitializeException("Steamのインストールが見つかりません。", error),
            EVRInitError.LastError => new EVRInitializeException("最後のエラーが発生しました。", error),

            _ => throw new ArgumentOutOfRangeException(nameof(error), error, $"予期しない初期化エラーが発生しました: {error}")
        };
    }
}